using System.Collections;
using UnityEngine;

/// <summary>
/// Tarefa #7 — Onça-pintada: salto ofensivo que impulsiona o corpo
/// automaticamente contra o inimigo mais próximo dentro de
/// <see cref="AnimalFormData.pounceRange"/> (ou na direcção em que o player
/// está virado, se nenhum inimigo estiver no alcance).
///
/// O dano é aplicado "de borla" via PlayerAttack.damageWhileDashing enquanto
/// motor.IsDashing estiver activo — tal como ChargeAbility, sem necessidade
/// de chamar EnemyHealth.TakeDamage directamente aqui.
/// </summary>
[RequireComponent(typeof(PlayerMotor2D), typeof(Rigidbody2D))]
public class PounceAbility : MonoBehaviour, IFormAbility, IAbility, IActiveAbility
{
    private bool enabledForForm;
    private AnimalFormData form;
    private PlayerMotor2D motor;
    private Rigidbody2D rb;

    private float cooldownTimer;
    private Coroutine pounceRoutine;

    /// <summary>true enquanto o salto ofensivo está em curso.</summary>
    public bool IsPouncing => pounceRoutine != null;

    private void Awake()
    {
        motor = GetComponent<PlayerMotor2D>();
        rb = GetComponent<Rigidbody2D>();
    }

    private void Update()
    {
        if (cooldownTimer > 0f) cooldownTimer -= Time.deltaTime;
    }

    public void ConfigureFromForm(AnimalFormData newForm)
    {
        form = newForm;
        enabledForForm = form != null && form.primaryAbility == PrimaryAbility.Pounce;
        if (!enabledForForm) StopPounceIfRunning();
    }

    /// <summary>Chamado pelo AbilityRouter (botão de Habilidade).</summary>
    public void TryPounce()
    {
        if (!enabledForForm || cooldownTimer > 0f || pounceRoutine != null) return;
        if (motor.MovementLocked) return;

        pounceRoutine = StartCoroutine(PounceRoutine());
    }

    private IEnumerator PounceRoutine()
    {
        cooldownTimer = form.pounceCooldown;

        Vector2 dir = FindTargetDirection();

        motor.SetMovementLocked(true, this);
        motor.SetDashing(true);

        float elapsed = 0f;
        while (elapsed < form.pounceDuration)
        {
            rb.velocity = dir * form.pounceSpeed;
            elapsed += Time.fixedDeltaTime;
            yield return new WaitForFixedUpdate();
        }

        EndPounce();
    }

    /// <summary>Direcção do inimigo mais próximo dentro de pounceRange, ou a direcção em que o player está virado.</summary>
    private Vector2 FindTargetDirection()
    {
        int facing = motor.FacingSign != 0 ? motor.FacingSign : 1;
        Vector2 fallback = new Vector2(facing, 0.35f).normalized;

        var hits = Physics2D.OverlapCircleAll(transform.position, form.pounceRange);
        EnemyHealth nearest = null;
        float bestDist = float.MaxValue;

        foreach (var hit in hits)
        {
            var enemyHealth = hit.GetComponentInParent<EnemyHealth>();
            if (enemyHealth == null) continue;

            float dist = Vector2.Distance(transform.position, hit.transform.position);
            if (dist < bestDist)
            {
                bestDist = dist;
                nearest = enemyHealth;
            }
        }

        if (nearest == null) return fallback;

        Vector2 toTarget = (Vector2)nearest.transform.position - (Vector2)transform.position;
        return toTarget.sqrMagnitude > 0.01f ? toTarget.normalized : fallback;
    }

    private void EndPounce()
    {
        motor.SetDashing(false);
        motor.SetMovementLocked(false, this);
        pounceRoutine = null;
    }

    private void StopPounceIfRunning()
    {
        if (pounceRoutine == null) return;
        StopCoroutine(pounceRoutine);
        EndPounce();
    }

    public void Cancel(AbilityCancelReason reason) => StopPounceIfRunning();

    void IAbility.Activate() => TryPounce();
    void IAbility.Release() { }
    public float CooldownRemaining => Mathf.Max(0f, cooldownTimer);
    bool IAbility.IsActive => pounceRoutine != null;
    public float CooldownDuration => form != null ? form.pounceCooldown : 0f;
    public bool CanActivate => enabledForForm && cooldownTimer <= 0f && pounceRoutine == null && !motor.MovementLocked;
    public void ResetCooldown() => cooldownTimer = 0f;
}
